private struct YouTubeMusicHomeScreen: View {
    var body: some View {
        ZStack(alignment: .bottom) {
            ScrollView {
                VStack(alignment: .leading, spacing: 20) {
                    Text("Bonsoir").font(.system(size: 28, weight: .bold)).foregroundStyle(YouTubeMusicTokens.ytmTextPrimary).padding(.horizontal)
                    LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 12) {
                        ForEach(YouTubeMusicDemoData.recent) { item in
                            YouTubeMusicRecentTile(item: item, surface: YouTubeMusicTokens.ytmSurface1)
                        }
                    }
                    .padding(.horizontal)
                    Text("Récemment joué").font(.system(size: 22, weight: .bold)).foregroundStyle(YouTubeMusicTokens.ytmTextPrimary).padding(.horizontal)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 12) {
                            ForEach(YouTubeMusicDemoData.playlists) { pl in
                                VStack(alignment: .leading) {
                                    RoundedRectangle(cornerRadius: 6).fill(pl.color).frame(width: 140, height: 140)
                                    Text(pl.title).font(.system(size: 14, weight: .semibold)).foregroundStyle(YouTubeMusicTokens.ytmTextPrimary).lineLimit(1)
                                }
                            }
                        }
                        .padding(.horizontal)
                    }
                }
                .padding(.vertical).padding(.bottom, 80)
            }
            .background(YouTubeMusicTokens.ytmCanvas.ignoresSafeArea())
            YouTubeMusicMiniPlayer(accent: YouTubeMusicTokens.ytmTextPrimary, surface: YouTubeMusicTokens.ytmSurface1, textPri: YouTubeMusicTokens.ytmTextPrimary)
        }
    }
}

